SELECT [Purchase Header].[Buy-from Vendor No_], Vendor.[Old Febos No_], Vendor.[Old Bridge No_], Vendor.Name, [Purchase Header].[Old Order No_], [Purchase Line].[Document No_] AS OrderNO, [Purchase Header].[Vendor Order No_], [Purchase Line].[Line No_], [Purchase Header].[Order Date] AS OrderDate, [Purchase Line].[Location Code], Item.[Trademark Code], Item.[Season Code], Item.[Line Code], Item.[Collection Code], Item.[Product Sex], [Purchase Line].[Delete Reason], [Purchase Line].No_ AS Article, Item.[Description 2] AS Description, [Purchase Line].[Constant Variable Code] AS Color, [Purchase Line].[Assortment Code], [Purchase Header].[Document Type], [Purchase Line].[Currency Code], Val([Purchase Line.Quantity]) AS QuantityPurchased, Val([Purchase Line.No_ of Pairs]) AS PairsPurchased, Val([purchase line.line amount]) AS ValuePurchased, Val([Purchase Line.Quantity Received]) AS QuantityReceived, IIf(Val([Purchase Line.quantity])>0,Val([Purchase Line.quantity received])/Val([Purchase Line.quantity])*Val([Purchase Line.no_ of pairs]),0) AS PairsReceived, IIf(Val([Purchase Line.quantity])>0,Val([Purchase Line.quantity received])/Val([Purchase Line.quantity])*Val([purchase line.line amount]),0) AS ValueReceived, Val([Purchase Line.Quantity Invoiced]) AS QuantityInvoicedPurchases, IIf(Val([Purchase Line.quantity])>0,Val([Purchase Line.quantity invoiced])/Val([Purchase Line.quantity])*Val([Purchase Line.no_ of pairs]),0) AS PairsInvoicedPurchases, IIf(Val([Purchase Line.quantity])>0,Val([Purchase Line.quantity invoiced])/Val([Purchase Line.quantity])*Val([purchase line.line amount]),0) AS ValueInvoicedPurchases, [Purchase Line].[Requested Receipt Date], [Purchase Line].[Promised Receipt Date], [Purchase Line].[Expected Receipt Date], Item.[Country_Region of Origin Code], Item.[Tariff No_], Item.[advertising material], Item.Manufacturer, Vendor_1.Name AS ManufacturerName
FROM ((([Purchase Header] INNER JOIN [Purchase Line] ON ([Purchase Header].No_ = [Purchase Line].[Document No_]) AND ([Purchase Header].[Document Type] = [Purchase Line].[Document Type])) INNER JOIN Item ON [Purchase Line].No_ = Item.No_) INNER JOIN Vendor ON [Purchase Header].[Buy-from Vendor No_] = Vendor.No_) LEFT JOIN Vendor AS Vendor_1 ON Item.Manufacturer = Vendor_1.No_
WHERE ((([Purchase Header].[Document Type])=1) AND (([Purchase Line].Type)=19 Or ([Purchase Line].Type)=20));

